using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models;

public class PersonTests
{
    [Fact]
    public void FullName_ReturnsLastNameCommaFirstName()
    {
        var student = new Student { LastName = "Smith", FirstMidName = "John" };
        Assert.Equal("Smith, John", student.FullName);
    }

    [Fact]
    public void FullName_WorksForInstructor()
    {
        var instructor = new Instructor
        {
            LastName = "Abercrombie",
            FirstMidName = "Kim",
            HireDate = DateTime.Now
        };
        Assert.Equal("Abercrombie, Kim", instructor.FullName);
    }
}

public class ErrorViewModelTests
{
    [Fact]
    public void ShowRequestId_ReturnsFalse_WhenRequestIdIsNull()
    {
        var model = new ErrorViewModel { RequestId = null };
        Assert.False(model.ShowRequestId);
    }

    [Fact]
    public void ShowRequestId_ReturnsFalse_WhenRequestIdIsEmpty()
    {
        var model = new ErrorViewModel { RequestId = "" };
        Assert.False(model.ShowRequestId);
    }

    [Fact]
    public void ShowRequestId_ReturnsTrue_WhenRequestIdHasValue()
    {
        var model = new ErrorViewModel { RequestId = "abc-123" };
        Assert.True(model.ShowRequestId);
    }
}

public class CourseModelTests
{
    [Fact]
    public void Course_PropertiesSetCorrectly()
    {
        var course = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = 1,
            TeachingMaterialImagePath = "/uploads/test.jpg"
        };

        Assert.Equal(1050, course.CourseID);
        Assert.Equal("Chemistry", course.Title);
        Assert.Equal(3, course.Credits);
        Assert.Equal(1, course.DepartmentID);
        Assert.Equal("/uploads/test.jpg", course.TeachingMaterialImagePath);
    }

    [Fact]
    public void Course_CollectionsCanBeNull()
    {
        var course = new Course();
        Assert.Null(course.Enrollments);
        Assert.Null(course.CourseAssignments);
        Assert.Null(course.Department);
    }
}

public class DepartmentModelTests
{
    [Fact]
    public void Department_PropertiesSetCorrectly()
    {
        var dept = new Department
        {
            DepartmentID = 1,
            Name = "Engineering",
            Budget = 350000m,
            StartDate = new DateTime(2007, 9, 1),
            InstructorID = 5
        };

        Assert.Equal(1, dept.DepartmentID);
        Assert.Equal("Engineering", dept.Name);
        Assert.Equal(350000m, dept.Budget);
        Assert.Equal(5, dept.InstructorID);
    }

    [Fact]
    public void Department_InstructorIDCanBeNull()
    {
        var dept = new Department { Name = "Test" };
        Assert.Null(dept.InstructorID);
    }
}

public class EnrollmentModelTests
{
    [Fact]
    public void Enrollment_GradeCanBeNull()
    {
        var enrollment = new Enrollment { EnrollmentID = 1, CourseID = 1, StudentID = 1 };
        Assert.Null(enrollment.Grade);
    }

    [Fact]
    public void Enrollment_GradeCanBeSet()
    {
        var enrollment = new Enrollment { Grade = Grade.A };
        Assert.Equal(Grade.A, enrollment.Grade);
    }

    [Theory]
    [InlineData(Grade.A)]
    [InlineData(Grade.B)]
    [InlineData(Grade.C)]
    [InlineData(Grade.D)]
    [InlineData(Grade.F)]
    public void Grade_AllValuesExist(Grade grade)
    {
        Assert.True(Enum.IsDefined(typeof(Grade), grade));
    }
}

public class NotificationModelTests
{
    [Fact]
    public void Notification_DefaultIsReadIsFalse()
    {
        var notification = new Notification();
        Assert.False(notification.IsRead);
    }

    [Fact]
    public void Notification_ReadAtCanBeNull()
    {
        var notification = new Notification();
        Assert.Null(notification.ReadAt);
    }

    [Fact]
    public void EntityOperation_HasAllValues()
    {
        Assert.Equal(0, (int)EntityOperation.CREATE);
        Assert.Equal(1, (int)EntityOperation.UPDATE);
        Assert.Equal(2, (int)EntityOperation.DELETE);
    }
}

public class CourseAssignmentModelTests
{
    [Fact]
    public void CourseAssignment_PropertiesSetCorrectly()
    {
        var ca = new CourseAssignment { CourseID = 1050, InstructorID = 10 };
        Assert.Equal(1050, ca.CourseID);
        Assert.Equal(10, ca.InstructorID);
    }
}

public class OfficeAssignmentModelTests
{
    [Fact]
    public void OfficeAssignment_PropertiesSetCorrectly()
    {
        var oa = new OfficeAssignment { InstructorID = 10, Location = "Room 101" };
        Assert.Equal(10, oa.InstructorID);
        Assert.Equal("Room 101", oa.Location);
    }
}

public class StudentModelTests
{
    [Fact]
    public void Student_InheritsFromPerson()
    {
        var student = new Student();
        Assert.IsAssignableFrom<Person>(student);
    }

    [Fact]
    public void Student_EnrollmentsCanBeNull()
    {
        var student = new Student();
        Assert.Null(student.Enrollments);
    }
}

public class InstructorModelTests
{
    [Fact]
    public void Instructor_InheritsFromPerson()
    {
        var instructor = new Instructor();
        Assert.IsAssignableFrom<Person>(instructor);
    }

    [Fact]
    public void Instructor_CourseAssignmentsCanBeNull()
    {
        var instructor = new Instructor();
        Assert.Null(instructor.CourseAssignments);
    }

    [Fact]
    public void Instructor_OfficeAssignmentCanBeNull()
    {
        var instructor = new Instructor();
        Assert.Null(instructor.OfficeAssignment);
    }
}

using ContosoUniversity.Models.SchoolViewModels;

namespace ContosoUniversity.Tests.Models;

public class AssignedCourseDataTests
{
    [Fact]
    public void Properties_SetCorrectly()
    {
        var data = new AssignedCourseData
        {
            CourseID = 1050,
            Title = "Chemistry",
            Assigned = true
        };

        Assert.Equal(1050, data.CourseID);
        Assert.Equal("Chemistry", data.Title);
        Assert.True(data.Assigned);
    }

    [Fact]
    public void Assigned_DefaultIsFalse()
    {
        var data = new AssignedCourseData();
        Assert.False(data.Assigned);
    }
}

public class EnrollmentDateGroupTests
{
    [Fact]
    public void Properties_SetCorrectly()
    {
        var date = new DateTime(2012, 9, 1);
        var group = new EnrollmentDateGroup
        {
            EnrollmentDate = date,
            StudentCount = 5
        };

        Assert.Equal(date, group.EnrollmentDate);
        Assert.Equal(5, group.StudentCount);
