    {
        // Seed students with different enrollment dates
        _context.Students.AddRange(
            new Student { FirstMidName = "A", LastName = "One", EnrollmentDate = DateTime.Parse("2010-09-01") },
            new Student { FirstMidName = "B", LastName = "Two", EnrollmentDate = DateTime.Parse("2010-09-01") },
