        Assert.NotNull(result);
        var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(result.Model);
        Assert.Equal(2, model.Count); // Two distinct enrollment dates
    }

    [Fact]
    public void About_GroupsStudentsCorrectly()
    {
        _context.Students.AddRange(
            new Student { FirstMidName = "A", LastName = "One", EnrollmentDate = DateTime.Parse("2010-09-01") },
            new Student { FirstMidName = "B", LastName = "Two", EnrollmentDate = DateTime.Parse("2010-09-01") },
            new Student { FirstMidName = "C", LastName = "Three", EnrollmentDate = DateTime.Parse("2012-09-01") }
        );
        _context.SaveChanges();

        var result = _controller.About() as ViewResult;
        var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(result!.Model);

        var group2010 = model.Single(g => g.EnrollmentDate == DateTime.Parse("2010-09-01"));
        Assert.Equal(2, group2010.StudentCount);

        var group2012 = model.Single(g => g.EnrollmentDate == DateTime.Parse("2012-09-01"));
        Assert.Equal(1, group2012.StudentCount);
    }

