namespace ContosoUniversity.Tests;

public class PaginatedListTests
{
    [Fact]
    public void Constructor_SetsPropertiesCorrectly()
    {
        var items = new List<string> { "a", "b", "c" };
        var list = new PaginatedList<string>(items, 10, 2, 3);

        Assert.Equal(2, list.PageIndex);
        Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
        Assert.Equal(3, list.Count);
    }

    [Fact]
    public void HasPreviousPage_TrueWhenPageIndexGreaterThan1()
    {
        var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
        Assert.True(list.HasPreviousPage);
    }

    [Fact]
    public void HasPreviousPage_FalseWhenPageIndexIs1()
    {
        var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
        Assert.False(list.HasPreviousPage);
    }

    [Fact]
    public void HasNextPage_TrueWhenMorePagesExist()
    {
        var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
        Assert.True(list.HasNextPage); // TotalPages = 2
    }

    [Fact]
    public void HasNextPage_FalseOnLastPage()
    {
        var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
        Assert.False(list.HasNextPage); // TotalPages = 2
    }

    [Fact]
    public void TotalPages_CalculatedCorrectly()
    {
        var list = new PaginatedList<int>(new List<int>(), 11, 1, 5);
        Assert.Equal(3, list.TotalPages); // ceil(11/5) = 3
    }

    [Fact]
    public void TotalPages_IsOneForSinglePage()
    {
        var list = new PaginatedList<int>(new List<int>(), 3, 1, 5);
        Assert.Equal(1, list.TotalPages);
    }

    [Fact]
    public void Create_ReturnsCorrectPage()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();
        var result = PaginatedList<int>.Create(source, 2, 10);

        Assert.Equal(2, result.PageIndex);
        Assert.Equal(3, result.TotalPages);
        Assert.Equal(10, result.Count);
        Assert.Equal(11, result[0]); // second page starts at 11
    }

    [Fact]
    public void Create_FirstPage()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();
        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.Equal(1, result.PageIndex);
        Assert.Equal(1, result[0]);
        Assert.Equal(10, result[9]);
    }

    [Fact]
    public void Create_LastPage_HasFewerItems()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();
        var result = PaginatedList<int>.Create(source, 3, 10);

        Assert.Equal(5, result.Count); // 25 - 20 = 5
        Assert.Equal(21, result[0]);
    }

    [Fact]
    public void Create_EmptySource()
    {
        var source = Enumerable.Empty<int>().AsQueryable();
        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.Equal(0, result.Count);
        Assert.Equal(0, result.TotalPages);
        Assert.False(result.HasPreviousPage);
        Assert.False(result.HasNextPage);
    }

    [Fact]
    public void Items_AreAccessibleByIndex()
    {
        var items = new List<string> { "alpha", "beta", "gamma" };
        var list = new PaginatedList<string>(items, 3, 1, 10);

        Assert.Equal("alpha", list[0]);
        Assert.Equal("beta", list[1]);
        Assert.Equal("gamma", list[2]);
    }
}

