using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests.Services;

public class NotificationServiceTests : IDisposable
{
    private readonly NotificationService _service;

    public NotificationServiceTests()
    {
        _service = new NotificationService();
        // Drain any leftover notifications from other tests (static queue)
        while (_service.ReceiveNotification() != null) { }
    }

    public void Dispose()
    {
        // Drain after test
        while (_service.ReceiveNotification() != null) { }
        _service.Dispose();
    }

    [Fact]
    public void SendNotification_EnqueuesNotification()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE, "TestUser");

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("1", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Equal("TestUser", notification.CreatedBy);
        Assert.False(notification.IsRead);
    }

    [Fact]
    public void SendNotification_WithDisplayName_IncludesNameInMessage()
    {
        _service.SendNotification("Course", "1050", "Chemistry", EntityOperation.CREATE, "Admin");

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("Chemistry", notification.Message);
        Assert.Contains("created", notification.Message);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        _service.SendNotification("Student", "42", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("ID: 42", notification.Message);
    }

    [Fact]
    public void SendNotification_DefaultUserIsSystem()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("System", notification.CreatedBy);
    }

    [Fact]
    public void SendNotification_UpdateOperation_MessageContainsUpdated()
    {
        _service.SendNotification("Department", "1", "Engineering", EntityOperation.UPDATE);

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("updated", notification.Message);
    }

    [Fact]
    public void SendNotification_DeleteOperation_MessageContainsDeleted()
    {
        _service.SendNotification("Instructor", "5", "Kim Abercrombie", EntityOperation.DELETE);

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("deleted", notification.Message);
    }

    [Fact]
    public void ReceiveNotification_ReturnsNull_WhenQueueEmpty()
    {
        var result = _service.ReceiveNotification();
        Assert.Null(result);
    }

    [Fact]
    public void ReceiveNotification_ReturnsInFIFOOrder()
    {
        _service.SendNotification("A", "1", EntityOperation.CREATE);
        _service.SendNotification("B", "2", EntityOperation.UPDATE);
        _service.SendNotification("C", "3", EntityOperation.DELETE);

        var first = _service.ReceiveNotification();
        var second = _service.ReceiveNotification();
        var third = _service.ReceiveNotification();

        Assert.Equal("A", first!.EntityType);
        Assert.Equal("B", second!.EntityType);
        Assert.Equal("C", third!.EntityType);
    }

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        var ex = Record.Exception(() => _service.MarkAsRead(999));
        Assert.Null(ex);
    }

    [Fact]
    public void SendNotification_SetsCreatedAt()
    {
        var before = DateTime.Now;
        _service.SendNotification("Test", "1", EntityOperation.CREATE);
        var after = DateTime.Now;

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.InRange(notification.CreatedAt, before, after);
    }

    [Fact]
    public void SendNotification_TwoParamOverload_Works()
    {
        _service.SendNotification("Student", "1", EntityOperation.UPDATE, "User1");

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("UPDATE", notification.Operation);
    }

    [Fact]
    public void Dispose_DoesNotThrow()
    {
        var service = new NotificationService();
        var ex = Record.Exception(() => service.Dispose());
        Assert.Null(ex);
    }
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

public class StudentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly StudentsController _controller;

    public StudentsControllerTests()
    {
        _context = TestHelpers.CreateContext();
        _controller = new StudentsController(_context);
        _controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private void SeedStudents()
    {
        _context.Students.AddRange(
            new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2010-09-01") },
            new Student { FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2012-09-01") },
            new Student { FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2013-09-01") },
            new Student { FirstMidName = "Yan", LastName = "Li", EnrollmentDate = DateTime.Parse("2012-09-01") }
        );
        _context.SaveChanges();
    }

    // --- Index tests ---

    [Fact]
    public void Index_ReturnsView_WithStudents()
    {
        SeedStudents();
        var result = _controller.Index(null, null, null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal(4, model.Count);
    }

    [Fact]
    public void Index_DefaultSort_OrdersByLastNameAscending()
    {
        SeedStudents();
        var result = _controller.Index(null, null, null, null) as ViewResult;
        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);

        Assert.Equal("Alexander", model[0].LastName);
        Assert.Equal("Alonso", model[1].LastName);
        Assert.Equal("Anand", model[2].LastName);
        Assert.Equal("Li", model[3].LastName);
    }

    [Fact]
    public void Index_NameDesc_OrdersByLastNameDescending()
    {
        SeedStudents();
        var result = _controller.Index("name_desc", null, null, null) as ViewResult;
        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);

        Assert.Equal("Li", model[0].LastName);
        Assert.Equal("Anand", model[1].LastName);
    }

    [Fact]
    public void Index_DateSort_OrdersByEnrollmentDateAscending()
    {
        SeedStudents();
        var result = _controller.Index("Date", null, null, null) as ViewResult;
        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);

        Assert.Equal("Alexander", model[0].LastName); // 2010
    }

    [Fact]
    public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
    {
        SeedStudents();
        var result = _controller.Index("date_desc", null, null, null) as ViewResult;
        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);

        Assert.Equal("Anand", model[0].LastName); // 2013
    }

    [Fact]
    public void Index_SearchByLastName_FiltersResults()
    {
        SeedStudents();
        var result = _controller.Index(null, null, "Al", null) as ViewResult;
        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);

        Assert.Equal(2, model.Count); // Alexander and Alonso
    }

    [Fact]
    public void Index_SearchByFirstName_FiltersResults()
    {
        SeedStudents();
        var result = _controller.Index(null, null, "Arturo", null) as ViewResult;
        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);

        Assert.Single(model);
        Assert.Equal("Anand", model[0].LastName);
    }

    [Fact]
    public void Index_SearchResetsToPage1()
    {
        SeedStudents();
        var result = _controller.Index(null, null, "Al", 5) as ViewResult;
        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);

        Assert.Equal(1, model.PageIndex);
    }

    [Fact]
    public void Index_NullSearchString_UsesCurrentFilter()
    {
        SeedStudents();
        var result = _controller.Index(null, "Alexander", null, null) as ViewResult;
        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);

        Assert.Single(model);
    }

    [Fact]
    public void Index_Pagination_LimitsResults()
    {
        for (int i = 0; i < 15; i++)
        {
            _context.Students.Add(new Student
            {
                FirstMidName = $"First{i}",
                LastName = $"Last{i:D2}",
                EnrollmentDate = DateTime.Parse("2020-01-01")
            });
        }
        _context.SaveChanges();

        var result = _controller.Index(null, null, null, 1) as ViewResult;
        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);

        Assert.Equal(10, model.Count);
        Assert.True(model.HasNextPage);
        Assert.False(model.HasPreviousPage);
    }

    [Fact]
    public void Index_Page2_HasPreviousPage()
    {
        for (int i = 0; i < 15; i++)
        {
            _context.Students.Add(new Student
            {
                FirstMidName = $"First{i}",
                LastName = $"Last{i:D2}",
                EnrollmentDate = DateTime.Parse("2020-01-01")
            });
