        var course = _context.Courses.Find(1050)!;
        _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var updated = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 };
        var mockFile = CreateMockFormFile("new.png", 2048);

        var result = _controller.Edit(updated, mockFile) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    // --- Delete GET ---

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);
        Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsView()
    {
        SeedCourses();
        var result = _controller.Delete(1050) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Course>(result.Model);
        Assert.Equal(1050, model.CourseID);
    }

    // --- Delete POST ---

    [Fact]
    public void DeleteConfirmed_RemovesCourse_RedirectsToIndex()
    {
        SeedCourses();
        var initialCount = _context.Courses.Count();

        var result = _controller.DeleteConfirmed(1050) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Equal(initialCount - 1, _context.Courses.Count());
    }

    [Fact]
    public void DeleteConfirmed_WithImage_DeletesFile()
    {
        SeedCourses();
        var course = _context.Courses.Find(1050)!;
        var uploadsDir = Path.Combine(_tempDir, "Uploads", "TeachingMaterials");
        Directory.CreateDirectory(uploadsDir);
        var filePath = Path.Combine(uploadsDir, "test_image.jpg");
        File.WriteAllText(filePath, "fake image data");
        course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test_image.jpg";
        _context.SaveChanges();

        _controller.DeleteConfirmed(1050);

        Assert.False(File.Exists(filePath));
    }

    // --- Helpers ---

    private static IFormFile CreateMockFormFile(string fileName, long length)
    {
        var mock = new Mock<IFormFile>();
        var stream = new MemoryStream(new byte[length]);
        mock.Setup(f => f.FileName).Returns(fileName);
        mock.Setup(f => f.Length).Returns(length);
        mock.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(s => stream.CopyTo(s));
        mock.Setup(f => f.OpenReadStream()).Returns(stream);
        return mock.Object;
    }
}

