    [Fact]
    public void DeleteConfirmed_WithImage_DeletesFile()
    {
        SeedCourses();
        var course = _context.Courses.Find(1050)!;
        var uploadsDir = Path.Combine(_tempDir, "Uploads", "TeachingMaterials");
        Directory.CreateDirectory(uploadsDir);
        var filePath = Path.Combine(uploadsDir, "test_image.jpg");
        File.WriteAllText(filePath, "fake image data");
        course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test_image.jpg";
        _context.SaveChanges();

        _controller.DeleteConfirmed(1050);

        Assert.False(File.Exists(filePath));
    }

    // --- Helpers ---

    private static IFormFile CreateMockFormFile(string fileName, long length)
    {
        var mock = new Mock<IFormFile>();
        var stream = new MemoryStream(new byte[length]);
        mock.Setup(f => f.FileName).Returns(fileName);
        mock.Setup(f => f.Length).Returns(length);
        mock.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(s => stream.CopyTo(s));
        mock.Setup(f => f.OpenReadStream()).Returns(stream);
        return mock.Object;
    }
}

