{
    private readonly SchoolContext _context;

    public SchoolContextTests()
    {
        _context = TestHelpers.CreateContext();
    }

    public void Dispose()
    {
        _context.Dispose();
    }

    [Fact]
    public void Context_HasStudentsDbSet()
    {
        Assert.NotNull(_context.Students);
    }

    [Fact]
    public void Context_HasCoursesDbSet()
    {
        Assert.NotNull(_context.Courses);
    }

    [Fact]
    public void Context_HasEnrollmentsDbSet()
    {
        Assert.NotNull(_context.Enrollments);
    }

    [Fact]
    public void Context_HasDepartmentsDbSet()
    {
        Assert.NotNull(_context.Departments);
    }

    [Fact]
    public void Context_HasInstructorsDbSet()
    {
        Assert.NotNull(_context.Instructors);
    }

    [Fact]
    public void Context_HasOfficeAssignmentsDbSet()
    {
        Assert.NotNull(_context.OfficeAssignments);
    }

    [Fact]
    public void Context_HasCourseAssignmentsDbSet()
    {
        Assert.NotNull(_context.CourseAssignments);
    }

    [Fact]
    public void Context_HasNotificationsDbSet()
    {
        Assert.NotNull(_context.Notifications);
    }

    [Fact]
    public void Context_HasPeopleDbSet()
    {
        Assert.NotNull(_context.People);
    }

    [Fact]
    public void Context_CanAddAndRetrieveStudent()
    {
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "User",
            EnrollmentDate = new DateTime(2020, 1, 1)
        };

        _context.Students.Add(student);
        _context.SaveChanges();

        var retrieved = _context.Students.First(s => s.LastName == "User");
        Assert.Equal("Test", retrieved.FirstMidName);
    }

    [Fact]
    public void Context_CanAddAndRetrieveInstructor()
    {
        var instructor = new Instructor
        {
            FirstMidName = "Test",
            LastName = "Prof",
            HireDate = new DateTime(2020, 1, 1)
        };

        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        var retrieved = _context.Instructors.First(i => i.LastName == "Prof");
        Assert.Equal("Test", retrieved.FirstMidName);
    }

    [Fact]
    public void Context_CanAddCourse()
    {
        TestHelpers.SeedDepartments(_context);

        var course = new Course
        {
            CourseID = 9999,
            Title = "Test Course",
            Credits = 3,
            DepartmentID = 1
        };

        _context.Courses.Add(course);
        _context.SaveChanges();

        var retrieved = _context.Courses.Find(9999);
        Assert.NotNull(retrieved);
        Assert.Equal("Test Course", retrieved.Title);
    }

    [Fact]
    public void Context_CanAddEnrollment()
    {
        TestHelpers.SeedFull(_context);

        var enrollment = new Enrollment
        {
            StudentID = 1,
            CourseID = 1045,
            Grade = Grade.A
        };

        _context.Enrollments.Add(enrollment);
        _context.SaveChanges();

        Assert.True(_context.Enrollments.Any(e => e.StudentID == 1 && e.CourseID == 1045 && e.Grade == Grade.A));
    }

    [Fact]
    public void Context_CourseAssignment_HasCompositeKey()
    {
        TestHelpers.SeedFull(_context);

        var ca = _context.CourseAssignments.Find(1050, 10);
        Assert.NotNull(ca);
    }

    [Fact]
    public void Context_CanAddNotification()
    {
        var notification = new Notification
        {
            EntityType = "Student",
            EntityId = "1",
            Operation = "CREATE",
            Message = "Test notification",
            CreatedAt = DateTime.Now,
            CreatedBy = "Test",
            IsRead = false
        };

        _context.Notifications.Add(notification);
        _context.SaveChanges();

        Assert.Equal(1, _context.Notifications.Count());
    }

    [Fact]
    public void Context_StudentInheritsPerson_TPH()
    {
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = DateTime.Now
        };

        _context.Students.Add(student);
        _context.SaveChanges();

        Assert.Equal(1, _context.Students.Count());
        Assert.Equal(1, _context.People.Count());
    }

    [Fact]
    public void Context_InstructorInheritsPerson_TPH()
    {
        var instructor = new Instructor
        {
            FirstMidName = "Test",
            LastName = "Instructor",
            HireDate = DateTime.Now
        };

        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        Assert.Equal(1, _context.Instructors.Count());
        Assert.Equal(1, _context.People.Count());
    }
}
