using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

public class StudentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly StudentsController _controller;

    public StudentsControllerTests()
    {
        _context = TestHelpers.CreateContext();
        _controller = new StudentsController(_context);
        _controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private void SeedStudents()
    {
        _context.Students.AddRange(
            new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2010-09-01") },
            new Student { FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2012-09-01") },
            new Student { FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2013-09-01") },
            new Student { FirstMidName = "Yan", LastName = "Li", EnrollmentDate = DateTime.Parse("2012-09-01") }
        );
        _context.SaveChanges();
    }

    // --- Index tests ---

    [Fact]
    public void Index_ReturnsView_WithStudents()
    {
        SeedStudents();
        var result = _controller.Index(null, null, null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal(4, model.Count);
    }

    [Fact]
    public void Index_DefaultSort_OrdersByLastNameAscending()
    {
        SeedStudents();
        var result = _controller.Index(null, null, null, null) as ViewResult;
        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);

        Assert.Equal("Alexander", model[0].LastName);
        Assert.Equal("Alonso", model[1].LastName);
        Assert.Equal("Anand", model[2].LastName);
        Assert.Equal("Li", model[3].LastName);
    }

    [Fact]
    public void Index_NameDesc_OrdersByLastNameDescending()
    {
        SeedStudents();
        var result = _controller.Index("name_desc", null, null, null) as ViewResult;
        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);

        Assert.Equal("Li", model[0].LastName);
        Assert.Equal("Anand", model[1].LastName);
    }

    [Fact]
    public void Index_DateSort_OrdersByEnrollmentDateAscending()
    {
        SeedStudents();
        var result = _controller.Index("Date", null, null, null) as ViewResult;
        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);

        Assert.Equal("Alexander", model[0].LastName); // 2010
    }

    [Fact]
    public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
    {
        SeedStudents();
        var result = _controller.Index("date_desc", null, null, null) as ViewResult;
        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);

        Assert.Equal("Anand", model[0].LastName); // 2013
    }

    [Fact]
    public void Index_SearchByLastName_FiltersResults()
    {
        SeedStudents();
        var result = _controller.Index(null, null, "Al", null) as ViewResult;
        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);

        Assert.Equal(2, model.Count); // Alexander and Alonso
    }

    [Fact]
    public void Index_SearchByFirstName_FiltersResults()
    {
        SeedStudents();
        var result = _controller.Index(null, null, "Arturo", null) as ViewResult;
        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);

        Assert.Single(model);
        Assert.Equal("Anand", model[0].LastName);
    }

    [Fact]
    public void Index_SearchResetsToPage1()
    {
        SeedStudents();
        var result = _controller.Index(null, null, "Al", 5) as ViewResult;
        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);

        Assert.Equal(1, model.PageIndex);
    }

    [Fact]
    public void Index_NullSearchString_UsesCurrentFilter()
    {
        SeedStudents();
        var result = _controller.Index(null, "Alexander", null, null) as ViewResult;
        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);

        Assert.Single(model);
    }

    [Fact]
    public void Index_Pagination_LimitsResults()
    {
        for (int i = 0; i < 15; i++)
        {
            _context.Students.Add(new Student
            {
                FirstMidName = $"First{i}",
                LastName = $"Last{i:D2}",
                EnrollmentDate = DateTime.Parse("2020-01-01")
            });
        }
        _context.SaveChanges();

        var result = _controller.Index(null, null, null, 1) as ViewResult;
        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);

        Assert.Equal(10, model.Count);
        Assert.True(model.HasNextPage);
        Assert.False(model.HasPreviousPage);
    }

    [Fact]
    public void Index_Page2_HasPreviousPage()
    {
        for (int i = 0; i < 15; i++)
        {
            _context.Students.Add(new Student
            {
                FirstMidName = $"First{i}",
                LastName = $"Last{i:D2}",
                EnrollmentDate = DateTime.Parse("2020-01-01")
            });
        }
        _context.SaveChanges();

        var result = _controller.Index(null, null, null, 2) as ViewResult;
        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);

        Assert.Equal(5, model.Count);
        Assert.True(model.HasPreviousPage);
        Assert.False(model.HasNextPage);
    }

    [Fact]
    public void Index_SetsViewBagSortParameters()
    {
        SeedStudents();
        _controller.Index(null, null, null, null);

        Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
        Assert.Equal("Date", _controller.ViewBag.DateSortParm);
    }

    [Fact]
    public void Index_WithSortOrder_SetsDateSortCorrectly()
    {
        SeedStudents();
        _controller.Index("Date", null, null, null);

        Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
    }

    // --- Details tests ---

    [Fact]
    public void Details_ReturnsNotFound_WhenIdIsNull()
    {
        var result = _controller.Details(null);
        Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
    }

    [Fact]
    public void Details_ReturnsView_WithStudent()
    {
        SeedStudents();
        var student = _context.Students.First();

        var result = _controller.Details(student.ID) as ViewResult;
        Assert.NotNull(result);
        var model = Assert.IsType<Student>(result.Model);
        Assert.Equal(student.ID, model.ID);
    }

    // --- Create GET tests ---

    [Fact]
    public void Create_Get_ReturnsView_WithDefaultDate()
    {
        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Student>(result.Model);
        Assert.Equal(DateTime.Today, model.EnrollmentDate);
    }

    // --- Create POST tests ---

    [Fact]
    public void Create_Post_ValidStudent_RedirectsToIndex()
    {
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = new DateTime(2020, 9, 1)
        };

        var result = _controller.Create(student) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Equal(1, _context.Students.Count());
    }

    [Fact]
    public void Create_Post_InvalidDate_MinValue_AddsModelError()
    {
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _controller.Create(student) as ViewResult;

        Assert.NotNull(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
    public void Create_Post_InvalidDate_Before1753_AddsModelError()
    {
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = new DateTime(1752, 12, 31)
        };

        var result = _controller.Create(student) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student { FirstMidName = "Test", EnrollmentDate = new DateTime(2020, 1, 1) };

        var result = _controller.Create(student) as ViewResult;

        Assert.NotNull(result);
        Assert.Equal(0, _context.Students.Count());
    }

    // --- Edit GET tests ---

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit(null);
        Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
    }

    [Fact]
    public void Edit_Get_NonExistentId_ReturnsNotFound()
    {
        var result = _controller.Edit(999);
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsView()
    {
        SeedStudents();
        var student = _context.Students.First();

        var result = _controller.Edit(student.ID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Student>(result.Model);
        Assert.Equal(student.ID, model.ID);
    }

    // --- Edit POST tests ---

    [Fact]
    public void Edit_Post_ValidStudent_RedirectsToIndex()
    {
        SeedStudents();
        var student = _context.Students.First();
        _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var updatedStudent = new Student
        {
            ID = student.ID,
            FirstMidName = "Updated",
            LastName = "Name",
            EnrollmentDate = new DateTime(2020, 1, 1)
        };

        var result = _controller.Edit(updatedStudent) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidDate_ReturnsView()
    {
        SeedStudents();
        var student = _context.Students.First();
        _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var updatedStudent = new Student
        {
            ID = student.ID,
            FirstMidName = "Updated",
            LastName = "Name",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _controller.Edit(updatedStudent) as ViewResult;

        Assert.NotNull(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    // --- Delete GET tests ---

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);
        Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
    }

    [Fact]
    public void Delete_Get_NonExistentId_ReturnsNotFound()
    {
        var result = _controller.Delete(999);
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsView()
    {
        SeedStudents();
        var student = _context.Students.First();

        var result = _controller.Delete(student.ID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Student>(result.Model);
        Assert.Equal(student.ID, model.ID);
    }

    // --- Delete POST tests ---

    [Fact]
    public void DeleteConfirmed_RemovesStudent_RedirectsToIndex()
    {
        SeedStudents();
        var student = _context.Students.First();
        var initialCount = _context.Students.Count();

        var result = _controller.DeleteConfirmed(student.ID) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Equal(initialCount - 1, _context.Students.Count());
    }
}

