using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Rendering;

namespace ContosoUniversity.Tests.Controllers;

public class DepartmentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly DepartmentsController _controller;

    public DepartmentsControllerTests()
    {
        _context = TestHelpers.CreateContext();
        _controller = new DepartmentsController(_context);
        _controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private void SeedDepartments()
    {
        TestHelpers.SeedDepartments(_context);
    }

    // --- Index tests ---

    [Fact]
    public void Index_ReturnsView_WithDepartments()
    {
        SeedDepartments();
        var result = _controller.Index() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsAssignableFrom<IEnumerable<Department>>(result.Model);
        Assert.Equal(2, model.Count());
    }

    // --- Details tests ---

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);
        Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
    }

    [Fact]
    public void Details_NonExistentId_ReturnsNotFound()
    {
        var result = _controller.Details(999);
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Details_ValidId_ReturnsView()
    {
        SeedDepartments();
        var dept = _context.Departments.First();

        var result = _controller.Details(dept.DepartmentID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Department>(result.Model);
        Assert.Equal(dept.DepartmentID, model.DepartmentID);
    }

    // --- Create GET ---

    [Fact]
    public void Create_Get_ReturnsView_WithInstructorSelectList()
    {
        SeedDepartments();
        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(_controller.ViewBag.InstructorID);
    }

    // --- Create POST ---

    [Fact]
    public void Create_Post_ValidDepartment_RedirectsToIndex()
    {
        TestHelpers.SeedInstructors(_context);

        var department = new Department
        {
            Name = "Physics",
            Budget = 200000,
            StartDate = new DateTime(2020, 9, 1),
            InstructorID = 10
        };

        var result = _controller.Create(department) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Equal(1, _context.Departments.Count());
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        TestHelpers.SeedInstructors(_context);
        _controller.ModelState.AddModelError("Name", "Required");

        var department = new Department { Budget = 100000, StartDate = DateTime.Now };

        var result = _controller.Create(department) as ViewResult;

        Assert.NotNull(result);
        Assert.Equal(0, _context.Departments.Count());
    }

    // --- Edit GET ---

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit(null);
        Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
    }

    [Fact]
    public void Edit_Get_NonExistentId_ReturnsNotFound()
    {
        var result = _controller.Edit(999);
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsView()
    {
        SeedDepartments();
        var dept = _context.Departments.First();

        var result = _controller.Edit(dept.DepartmentID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Department>(result.Model);
        Assert.Equal(dept.DepartmentID, model.DepartmentID);
    }

    // --- Edit POST ---

    [Fact]
    public void Edit_Post_ValidDepartment_RedirectsToIndex()
    {
        SeedDepartments();
        var dept = _context.Departments.First();
        _context.Entry(dept).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var updated = new Department
        {
            DepartmentID = dept.DepartmentID,
            Name = "Updated Dept",
            Budget = 500000,
            StartDate = new DateTime(2020, 1, 1),
            InstructorID = 10
        };

        var result = _controller.Edit(updated) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidModelState_ReturnsView()
    {
        SeedDepartments();
        _controller.ModelState.AddModelError("Name", "Required");
        var dept = new Department { DepartmentID = 1, Budget = 100, StartDate = DateTime.Now };

        var result = _controller.Edit(dept) as ViewResult;

        Assert.NotNull(result);
    }

    // --- Delete GET ---

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);
        Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
    }

    [Fact]
    public void Delete_Get_NonExistentId_ReturnsNotFound()
    {
        var result = _controller.Delete(999);
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsView()
    {
        SeedDepartments();
        var dept = _context.Departments.First();

        var result = _controller.Delete(dept.DepartmentID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Department>(result.Model);
        Assert.Equal(dept.DepartmentID, model.DepartmentID);
    }

    // --- Delete POST ---

    [Fact]
    public void DeleteConfirmed_RemovesDepartment_RedirectsToIndex()
    {
        SeedDepartments();
        var dept = _context.Departments.First();
        var initialCount = _context.Departments.Count();

        var result = _controller.DeleteConfirmed(dept.DepartmentID) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Equal(initialCount - 1, _context.Departments.Count());
    }
}

