using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;

namespace ContosoUniversity.Tests.Controllers;

public class CoursesControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly CoursesController _controller;
    private readonly Mock<IWebHostEnvironment> _mockEnv;
    private readonly Mock<ILogger<CoursesController>> _mockLogger;
    private readonly string _tempDir;

    public CoursesControllerTests()
    {
        _context = TestHelpers.CreateContext();
        _mockEnv = new Mock<IWebHostEnvironment>();
        _mockLogger = new Mock<ILogger<CoursesController>>();
        _tempDir = Path.Combine(Path.GetTempPath(), "contoso_test_" + Guid.NewGuid().ToString("N"));
        Directory.CreateDirectory(_tempDir);
        _mockEnv.Setup(e => e.WebRootPath).Returns(_tempDir);
        _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempDir);

        _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        _controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
        if (Directory.Exists(_tempDir))
        {
            try { Directory.Delete(_tempDir, true); } catch { }
        }
    }

    private void SeedCourses()
    {
        TestHelpers.SeedCourses(_context);
    }

    // --- Index ---

    [Fact]
    public void Index_ReturnsView_WithCourses()
    {
        SeedCourses();
        var result = _controller.Index() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsAssignableFrom<IEnumerable<Course>>(result.Model);
        Assert.Equal(3, model.Count());
    }

    // --- Details ---

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);
        Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
    }

    [Fact]
    public void Details_ValidId_ReturnsView()
    {
        SeedCourses();

        var result = _controller.Details(1050) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Course>(result.Model);
        Assert.Equal(1050, model.CourseID);
    }

    // --- Create GET ---

    [Fact]
    public void Create_Get_ReturnsView_WithDepartmentSelectList()
    {
        SeedCourses();
        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(_controller.ViewBag.DepartmentID);
        var model = Assert.IsType<Course>(result.Model);
    }

    // --- Create POST ---

    [Fact]
    public void Create_Post_ValidCourse_NoImage_RedirectsToIndex()
    {
        SeedCourses();
        var course = new Course
        {
            CourseID = 9999,
            Title = "New Course",
            Credits = 3,
            DepartmentID = 1
        };

        var result = _controller.Create(course, null!) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.NotNull(_context.Courses.Find(9999));
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        SeedCourses();
        _controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 9999, Credits = 3, DepartmentID = 1 };

        var result = _controller.Create(course, null!) as ViewResult;

        Assert.NotNull(result);
        Assert.Null(_context.Courses.Find(9999));
    }

    [Fact]
    public void Create_Post_InvalidImageExtension_ReturnsViewWithError()
    {
        SeedCourses();
        var course = new Course { CourseID = 9999, Title = "Test", Credits = 3, DepartmentID = 1 };
        var mockFile = CreateMockFormFile("test.txt", 1024);

        var result = _controller.Create(course, mockFile) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Create_Post_ImageTooLarge_ReturnsViewWithError()
    {
        SeedCourses();
        var course = new Course { CourseID = 9999, Title = "Test", Credits = 3, DepartmentID = 1 };
        var mockFile = CreateMockFormFile("test.jpg", 6 * 1024 * 1024); // 6MB

        var result = _controller.Create(course, mockFile) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Create_Post_ValidImage_UploadsFile()
    {
        SeedCourses();
        var course = new Course { CourseID = 9999, Title = "Test", Credits = 3, DepartmentID = 1 };
        var mockFile = CreateMockFormFile("test.jpg", 1024);

        var result = _controller.Create(course, mockFile) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        var saved = _context.Courses.Find(9999);
        Assert.NotNull(saved);
        Assert.StartsWith("/Uploads/TeachingMaterials/", saved.TeachingMaterialImagePath);
    }

    [Theory]
    [InlineData(".jpg")]
    [InlineData(".jpeg")]
    [InlineData(".png")]
    [InlineData(".gif")]
    [InlineData(".bmp")]
    public void Create_Post_AllowedExtensions_Accepted(string ext)
    {
        SeedCourses();
        var courseId = 9000 + ext.GetHashCode() % 1000;
        var course = new Course { CourseID = courseId, Title = "Test", Credits = 3, DepartmentID = 1 };
        var mockFile = CreateMockFormFile($"test{ext}", 1024);

        var result = _controller.Create(course, mockFile) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    // --- Edit GET ---

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit((int?)null);
        Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
    }

    [Fact]
    public void Edit_Get_NonExistentId_ReturnsNotFound()
    {
        var result = _controller.Edit(999);
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsView()
    {
        SeedCourses();
        var result = _controller.Edit(1050) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Course>(result.Model);
        Assert.Equal(1050, model.CourseID);
    }

    // --- Edit POST ---

    [Fact]
    public void Edit_Post_ValidCourse_NoImage_RedirectsToIndex()
    {
        SeedCourses();
        var course = _context.Courses.Find(1050)!;
        _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var updated = new Course
        {
            CourseID = 1050,
            Title = "Updated Chemistry",
            Credits = 4,
            DepartmentID = 1
        };

        var result = _controller.Edit(updated, null!) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidModelState_ReturnsView()
    {
        SeedCourses();
        _controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 1050, Credits = 3, DepartmentID = 1 };

        var result = _controller.Edit(course, null!) as ViewResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_Post_InvalidImageExtension_ReturnsViewWithError()
    {
        SeedCourses();
        var course = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 };
        var mockFile = CreateMockFormFile("bad.exe", 1024);

        var result = _controller.Edit(course, mockFile) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Edit_Post_ImageTooLarge_ReturnsViewWithError()
    {
        SeedCourses();
        var course = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 };
        var mockFile = CreateMockFormFile("big.png", 6 * 1024 * 1024);

        var result = _controller.Edit(course, mockFile) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Edit_Post_ValidImage_UploadsFile()
    {
        SeedCourses();
        var course = _context.Courses.Find(1050)!;
        _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var updated = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 };
        var mockFile = CreateMockFormFile("new.png", 2048);

        var result = _controller.Edit(updated, mockFile) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    // --- Delete GET ---

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);
        Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsView()
    {
        SeedCourses();
        var result = _controller.Delete(1050) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Course>(result.Model);
        Assert.Equal(1050, model.CourseID);
    }

    // --- Delete POST ---

    [Fact]
    public void DeleteConfirmed_RemovesCourse_RedirectsToIndex()
    {
        SeedCourses();
        var initialCount = _context.Courses.Count();

        var result = _controller.DeleteConfirmed(1050) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Equal(initialCount - 1, _context.Courses.Count());
    }

    [Fact]
    public void DeleteConfirmed_WithImage_DeletesFile()
    {
        SeedCourses();
        var course = _context.Courses.Find(1050)!;
        var uploadsDir = Path.Combine(_tempDir, "Uploads", "TeachingMaterials");
        Directory.CreateDirectory(uploadsDir);
        var filePath = Path.Combine(uploadsDir, "test_image.jpg");
        File.WriteAllText(filePath, "fake image data");
        course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test_image.jpg";
        _context.SaveChanges();

        _controller.DeleteConfirmed(1050);

        Assert.False(File.Exists(filePath));
    }

    // --- Helpers ---

    private static IFormFile CreateMockFormFile(string fileName, long length)
    {
        var mock = new Mock<IFormFile>();
        var stream = new MemoryStream(new byte[length]);
        mock.Setup(f => f.FileName).Returns(fileName);
        mock.Setup(f => f.Length).Returns(length);
        mock.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(s => stream.CopyTo(s));
        mock.Setup(f => f.OpenReadStream()).Returns(stream);
        return mock.Object;
    }
}

