using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

public class InstructorsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly InstructorsController _controller;

    public InstructorsControllerTests()
    {
        _context = TestHelpers.CreateContext();
        _controller = new InstructorsController(_context);
        _controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private void SeedFull()
    {
        TestHelpers.SeedFull(_context);
    }

    // --- Index ---

    [Fact]
    public void Index_ReturnsView_WithInstructors()
    {
        SeedFull();
        var result = _controller.Index(null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<InstructorIndexData>(result.Model);
        Assert.Equal(2, model.Instructors.Count());
    }

    [Fact]
    public void Index_WithInstructorId_PopulatesCourses()
    {
        SeedFull();
        var result = _controller.Index(10, null) as ViewResult;

        var model = Assert.IsType<InstructorIndexData>(result!.Model);
        Assert.NotNull(model.Courses);
        Assert.Single(model.Courses);
    }

    [Fact]
    public void Index_WithCourseId_PopulatesEnrollments()
    {
        SeedFull();
        var result = _controller.Index(10, 1050) as ViewResult;

        var model = Assert.IsType<InstructorIndexData>(result!.Model);
        Assert.NotNull(model.Enrollments);
    }

    [Fact]
    public void Index_NoIds_CoursesAndEnrollmentsAreNull()
    {
        SeedFull();
        var result = _controller.Index(null, null) as ViewResult;

        var model = Assert.IsType<InstructorIndexData>(result!.Model);
        Assert.Null(model.Courses);
        Assert.Null(model.Enrollments);
    }

    // --- Details ---

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);
        Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
    }

    [Fact]
    public void Details_NonExistentId_ReturnsNotFound()
    {
        var result = _controller.Details(999);
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Details_ValidId_ReturnsView()
    {
        SeedFull();
        var result = _controller.Details(10) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Instructor>(result.Model);
        Assert.Equal(10, model.ID);
    }

    // --- Create GET ---

    [Fact]
    public void Create_Get_ReturnsView_WithNewInstructor()
    {
        SeedFull();
        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Instructor>(result.Model);
        Assert.NotNull(model.CourseAssignments);
        Assert.Empty(model.CourseAssignments);
    }

    [Fact]
    public void Create_Get_PopulatesAssignedCourseData()
    {
        SeedFull();
        _controller.Create();

        var courses = _controller.ViewBag.Courses as List<AssignedCourseData>;
        Assert.NotNull(courses);
        Assert.Equal(3, courses.Count);
        Assert.All(courses, c => Assert.False(c.Assigned));
    }

    // --- Create POST ---

    [Fact]
    public void Create_Post_ValidInstructor_NoSelectedCourses_RedirectsToIndex()
    {
        SeedFull();
        var instructor = new Instructor
        {
            FirstMidName = "New",
            LastName = "Instructor",
            HireDate = new DateTime(2020, 1, 1)
        };

        var result = _controller.Create(instructor, null!) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Create_Post_WithSelectedCourses_CreatesCourseAssignments()
    {
        SeedFull();
        var instructor = new Instructor
        {
            FirstMidName = "New",
            LastName = "Instructor",
            HireDate = new DateTime(2020, 1, 1)
        };

        var selectedCourses = new[] { "1050", "4022" };

        var result = _controller.Create(instructor, selectedCourses) as RedirectToActionResult;

        Assert.NotNull(result);
        var savedInstructor = _context.Instructors
            .Where(i => i.LastName == "Instructor")
            .FirstOrDefault();
        Assert.NotNull(savedInstructor);
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        SeedFull();
        _controller.ModelState.AddModelError("LastName", "Required");
        var instructor = new Instructor
        {
            FirstMidName = "Test",
            HireDate = DateTime.Now,
            CourseAssignments = new List<CourseAssignment>()
        };

        var result = _controller.Create(instructor, null!) as ViewResult;

        Assert.NotNull(result);
    }

    // --- Edit GET ---

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit((int?)null);
        Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsView()
    {
        SeedFull();
        var result = _controller.Edit((int?)10) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Instructor>(result.Model);
        Assert.Equal(10, model.ID);
    }

    [Fact]
    public void Edit_Get_PopulatesAssignedCourseData()
    {
        SeedFull();
        _controller.Edit((int?)10);

        var courses = _controller.ViewBag.Courses as List<AssignedCourseData>;
        Assert.NotNull(courses);
        Assert.Contains(courses, c => c.CourseID == 1050 && c.Assigned);
    }

    // --- Delete GET ---

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);
        Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
    }

    [Fact]
    public void Delete_Get_NonExistentId_ReturnsNotFound()
    {
        var result = _controller.Delete(999);
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsView()
    {
        SeedFull();
        var result = _controller.Delete(10) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Instructor>(result.Model);
        Assert.Equal(10, model.ID);
    }

    // --- Delete POST ---

    [Fact]
    public void DeleteConfirmed_RemovesInstructor_RedirectsToIndex()
    {
        SeedFull();
        var initialCount = _context.Instructors.Count();

        var result = _controller.DeleteConfirmed(10) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Equal(initialCount - 1, _context.Instructors.Count());
    }

    [Fact]
    public void DeleteConfirmed_NullsDepartmentAdministrator()
    {
