using ContosoUniversity.Data;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Data;

public class DbInitializerTests : IDisposable
{
    private readonly SchoolContext _context;

    public DbInitializerTests()
    {
        _context = TestHelpers.CreateContext();
    }

    public void Dispose()
    {
        _context.Dispose();
    }

    [Fact]
    public void Initialize_SeedsStudents()
    {
        DbInitializer.Initialize(_context);
        Assert.Equal(8, _context.Students.Count());
    }

    [Fact]
    public void Initialize_SeedsInstructors()
    {
        DbInitializer.Initialize(_context);
        Assert.Equal(5, _context.Instructors.Count());
    }

    [Fact]
    public void Initialize_SeedsDepartments()
    {
        DbInitializer.Initialize(_context);
        Assert.Equal(4, _context.Departments.Count());
    }

    [Fact]
    public void Initialize_SeedsCourses()
    {
        DbInitializer.Initialize(_context);
        Assert.Equal(7, _context.Courses.Count());
    }

    [Fact]
    public void Initialize_SeedsEnrollments()
    {
        DbInitializer.Initialize(_context);
        Assert.Equal(11, _context.Enrollments.Count());
    }

    [Fact]
    public void Initialize_SeedsOfficeAssignments()
    {
        DbInitializer.Initialize(_context);
        Assert.Equal(3, _context.OfficeAssignments.Count());
    }

    [Fact]
    public void Initialize_SeedsCourseAssignments()
    {
        DbInitializer.Initialize(_context);
        Assert.Equal(8, _context.CourseAssignments.Count());
    }

    [Fact]
    public void Initialize_DoesNotReseed_WhenDataExists()
    {
        DbInitializer.Initialize(_context);
        var firstStudentCount = _context.Students.Count();

        DbInitializer.Initialize(_context);
        Assert.Equal(firstStudentCount, _context.Students.Count());
    }

    [Fact]
    public void Initialize_StudentData_HasCorrectFirstStudent()
    {
        DbInitializer.Initialize(_context);
        var student = _context.Students.FirstOrDefault(s => s.LastName == "Alexander");

        Assert.NotNull(student);
        Assert.Equal("Carson", student.FirstMidName);
        Assert.Equal(DateTime.Parse("2010-09-01"), student.EnrollmentDate);
    }

    [Fact]
    public void Initialize_DepartmentData_HasBudgets()
    {
        DbInitializer.Initialize(_context);
        var english = _context.Departments.FirstOrDefault(d => d.Name == "English");

        Assert.NotNull(english);
        Assert.Equal(350000m, english.Budget);
    }

    [Fact]
    public void Initialize_CourseData_HasCorrectCredits()
    {
        DbInitializer.Initialize(_context);
        var chemistry = _context.Courses.FirstOrDefault(c => c.Title == "Chemistry");

        Assert.NotNull(chemistry);
        Assert.Equal(3, chemistry.Credits);
        Assert.Equal(1050, chemistry.CourseID);
    }

    [Fact]
    public void Initialize_DepartmentsHaveAdministrators()
    {
        DbInitializer.Initialize(_context);
        var departments = _context.Departments.ToList();

        Assert.All(departments, d => Assert.NotNull(d.InstructorID));
    }

    [Fact]
    public void Initialize_EnrollmentsHaveGrades()
    {
        DbInitializer.Initialize(_context);
        var enrollmentsWithGrades = _context.Enrollments.Where(e => e.Grade != null).Count();

        Assert.True(enrollmentsWithGrades > 0);
    }

    [Fact]
    public void Initialize_SomeEnrollmentsHaveNoGrade()
    {
        DbInitializer.Initialize(_context);
        var enrollmentsWithoutGrades = _context.Enrollments.Where(e => e.Grade == null).Count();

        Assert.True(enrollmentsWithoutGrades > 0);
    }
}

